query:
SELECT COUNT(*) as doc_links FROM actor_document_links;
SELECT COUNT(*) as timeline_links FROM actor_timeline_links;
SELECT a.name, COUNT(adl.id) as doc_count FROM actors a LEFT JOIN actor_document_links adl ON a.id = adl.actor_id GROUP BY a.id, a.name ORDER BY doc_count DESC LIMIT 10;

